import { z as z157 } from "zod";
import { desc as desc6, eq as eq6, and as and5 } from "drizzle-orm";
import { TRPCError as TRPCError3 } from "@trpc/server";
var governanceRouter = router({
  // Get all proposals
  getProposals: publicProcedure.input(z157.object({
    status: z157.enum(["draft", "active", "passed", "rejected", "executed", "all"]).default("all"),
    limit: z157.number().default(20),
    offset: z157.number().default(0)
  })).query(async ({ input }) => {
    const db = await getDb();
    if (!db) return [];
    const query = db.select({
      id: proposals.id,
      title: proposals.title,
      description: proposals.description,
      category: proposals.category,
      status: proposals.status,
      votesFor: proposals.votesFor,
      votesAgainst: proposals.votesAgainst,
      votesAbstain: proposals.votesAbstain,
      quorum: proposals.quorum,
      requiredApproval: proposals.requiredApproval,
      endsAt: proposals.endsAt,
      executedAt: proposals.executedAt,
      onChainId: proposals.onChainId,
      createdAt: proposals.createdAt,
      authorName: users2.name,
      authorUsername: users2.username,
      authorAvatar: users2.avatarUrl
    }).from(proposals).leftJoin(users2, eq6(proposals.authorId, users2.id)).orderBy(desc6(proposals.createdAt)).limit(input.limit).offset(input.offset);
    if (input.status !== "all") {
      return (await query).filter((p) => p.status === input.status);
    }
    return query;
  }),
  // Get single proposal
  getProposal: publicProcedure.input(z157.object({ id: z157.number() })).query(async ({ input }) => {
    const db = await getDb();
    if (!db) return null;
    const result = await db.select().from(proposals).where(eq6(proposals.id, input.id)).limit(1);
    return result[0] || null;
  }),
  // Create a proposal
  createProposal: protectedProcedure.input(z157.object({
    title: z157.string().min(10).max(256),
    description: z157.string().min(50).max(1e4),
    category: z157.enum(["protocol", "treasury", "feature", "partnership", "emergency"]),
    endsAt: z157.string(),
    // ISO date string
    quorum: z157.number().default(1e3)
  })).mutation(async ({ input, ctx }) => {
    const db = await getDb();
    if (!db) throw new Error("Database unavailable");
    const wallet = await db.select().from(wallets).where(eq6(wallets.userId, ctx.user.id)).limit(1);
    const skyBalance = parseFloat(String(wallet[0]?.skyBalance || "0"));
    if (skyBalance < 100) {
      throw new TRPCError3({ code: "FORBIDDEN", message: "You need at least 100 SKY to create a proposal" });
    }
    const [result] = await db.insert(proposals).values({
      authorId: ctx.user.id,
      title: input.title,
      description: input.description,
      category: input.category,
      status: "active",
      quorum: input.quorum,
      endsAt: new Date(input.endsAt)
    });
    return { success: true, proposalId: result.insertId };
  }),
  // Vote on a proposal
  vote: protectedProcedure.input(z157.object({
    proposalId: z157.number(),
    vote: z157.enum(["for", "against", "abstain"])
  })).mutation(async ({ input, ctx }) => {
    const db = await getDb();
    if (!db) throw new Error("Database unavailable");
    const existing = await db.select().from(votes).where(and5(eq6(votes.proposalId, input.proposalId), eq6(votes.userId, ctx.user.id))).limit(1);
    if (existing.length > 0) {
      throw new TRPCError3({ code: "BAD_REQUEST", message: "You have already voted on this proposal" });
    }
    const wallet = await db.select().from(wallets).where(eq6(wallets.userId, ctx.user.id)).limit(1);
    const votingPower = Math.max(1, Math.floor(parseFloat(String(wallet[0]?.skyBalance || "1"))));
    await db.insert(votes).values({
      proposalId: input.proposalId,
      userId: ctx.user.id,
      choice: input.vote,
      votingPower: votingPower.toString()
    });
    const updateField = input.vote === "for" ? { votesFor: proposals.votesFor } : input.vote === "against" ? { votesAgainst: proposals.votesAgainst } : { votesAbstain: proposals.votesAbstain };
    const { sql: sql24 } = await import("drizzle-orm");
    if (input.vote === "for") {
      await db.update(proposals).set({ votesFor: sql24`${proposals.votesFor} + ${votingPower}` }).where(eq6(proposals.id, input.proposalId));
    } else if (input.vote === "against") {
      await db.update(proposals).set({ votesAgainst: sql24`${proposals.votesAgainst} + ${votingPower}` }).where(eq6(proposals.id, input.proposalId));
    } else {
      await db.update(proposals).set({ votesAbstain: sql24`${proposals.votesAbstain} + ${votingPower}` }).where(eq6(proposals.id, input.proposalId));
    }
    return { success: true, votingPower };
  }),
  // Get user's vote on a proposal
  getUserVote: protectedProcedure.input(z157.object({ proposalId: z157.number() })).query(async ({ input, ctx }) => {
    const db = await getDb();
    if (!db) return null;
    const result = await db.select().from(votes).where(and5(eq6(votes.proposalId, input.proposalId), eq6(votes.userId, ctx.user.id))).limit(1);
    return result[0] || null;
  }),
  // Get DAO stats
  getStats: publicProcedure.query(async () => {
    const db = await getDb();
    if (!db) return { totalProposals: 0, activeProposals: 0, totalVotes: 0, treasuryBalance: "0" };
    const allProposals = await db.select({ status: proposals.status }).from(proposals);
    const allVotes = await db.select({ id: votes.id }).from(votes);
    return {
      totalProposals: allProposals.length,
      activeProposals: allProposals.filter((p) => p.status === "active").length,
      totalVotes: allVotes.length,
      treasuryBalance: "2,847,293.44"
    };
  })
});

