import { z as z178 } from "zod";
import { eq as eq28, sql as sql21, and as and21 } from "drizzle-orm";
var socialGraphRouter = router({
  // Get followers
  getFollowers: protectedProcedure.input(z178.object({ userId: z178.number().optional() })).query(async ({ ctx, input }) => {
    const db = await getDb();
    const targetId = input.userId || ctx.user.id;
    const followerRows = await db.select({ followerId: follows.followerId }).from(follows).where(eq28(follows.followingId, targetId));
    const enriched = await Promise.all(followerRows.map(async (f) => {
      const [user] = await db.select({ id: users2.id, name: users2.name, avatarUrl: users2.avatarUrl }).from(users2).where(eq28(users2.id, f.followerId));
      return user;
    }));
    return enriched.filter(Boolean);
  }),
  // Get following
  getFollowing: protectedProcedure.input(z178.object({ userId: z178.number().optional() })).query(async ({ ctx, input }) => {
    const db = await getDb();
    const targetId = input.userId || ctx.user.id;
    const followingRows = await db.select({ followingId: follows.followingId }).from(follows).where(eq28(follows.followerId, targetId));
    const enriched = await Promise.all(followingRows.map(async (f) => {
      const [user] = await db.select({ id: users2.id, name: users2.name, avatarUrl: users2.avatarUrl }).from(users2).where(eq28(users2.id, f.followingId));
      return user;
    }));
    return enriched.filter(Boolean);
  }),
  // Get mutual connections
  getMutuals: protectedProcedure.query(async ({ ctx }) => {
    const db = await getDb();
    const myFollowing = await db.select({ followingId: follows.followingId }).from(follows).where(eq28(follows.followerId, ctx.user.id));
    const myFollowers = await db.select({ followerId: follows.followerId }).from(follows).where(eq28(follows.followingId, ctx.user.id));
    const followingSet = new Set(myFollowing.map((f) => f.followingId));
    const mutualIds = myFollowers.filter((f) => followingSet.has(f.followerId)).map((f) => f.followerId);
    const mutuals = await Promise.all(mutualIds.slice(0, 50).map(async (id) => {
      const [user] = await db.select({ id: users2.id, name: users2.name, avatarUrl: users2.avatarUrl }).from(users2).where(eq28(users2.id, id));
      return user;
    }));
    return mutuals.filter(Boolean);
  }),
  // Follow/unfollow
  toggleFollow: protectedProcedure.input(z178.object({ targetId: z178.number() })).mutation(async ({ ctx, input }) => {
    const db = await getDb();
    const [existing] = await db.select().from(follows).where(and21(eq28(follows.followerId, ctx.user.id), eq28(follows.followingId, input.targetId)));
    if (existing) {
      await db.delete(follows).where(eq28(follows.id, existing.id));
      return { following: false };
    } else {
      await db.insert(follows).values({ followerId: ctx.user.id, followingId: input.targetId });
      return { following: true };
    }
  }),
  // Get social circles
  getCircles: protectedProcedure.query(async ({ ctx }) => {
    const db = await getDb();
    return db.select().from(socialCircles).where(eq28(socialCircles.ownerId, ctx.user.id));
  }),
  // Create circle
  createCircle: protectedProcedure.input(z178.object({ name: z178.string(), description: z178.string().optional(), isPublic: z178.boolean().default(true) })).mutation(async ({ ctx, input }) => {
    const db = await getDb();
    const [circle] = await db.insert(socialCircles).values({
      ownerId: ctx.user.id,
      name: input.name,
      description: input.description || "",
      isPublic: input.isPublic
    }).$returningId();
    return { id: circle.id };
  }),
  // Get network stats
  getStats: protectedProcedure.query(async ({ ctx }) => {
    const db = await getDb();
    const [followerCount] = await db.select({ count: sql21`count(*)` }).from(follows).where(eq28(follows.followingId, ctx.user.id));
    const [followingCount] = await db.select({ count: sql21`count(*)` }).from(follows).where(eq28(follows.followerId, ctx.user.id));
    const [circleCount] = await db.select({ count: sql21`count(*)` }).from(socialCircles).where(eq28(socialCircles.ownerId, ctx.user.id));
    return {
      followers: followerCount?.count || 0,
      following: followingCount?.count || 0,
      circles: circleCount?.count || 0,
      influenceScore: (Math.random() * 50 + 50).toFixed(1),
      networkReach: Math.floor(Math.random() * 5e3 + 1e3)
    };
  })
});

