    if (!stake) throw new Error("Stake not found");
    const daysStaked = Math.floor((Date.now() - stake.stakedAt.getTime()) / 864e5);
    const reward = (parseFloat(stake.amount) * parseFloat(stake.apy) / 100 * daysStaked / 365).toFixed(8);
    await db.update(stakingPositions).set({ rewards: reward }).where(eq31(stakingPositions.id, input.stakeId));
