    if (existing) {
      await db.update(minerPositions).set({ isActive: true, hashRate: input.hashRate }).where(eq31(minerPositions.id, existing.id));
      return { id: existing.id, status: "resumed" };
    }
    const [pos] = await db.insert(minerPositions).values({
      userId: ctx.user.id,
      poolId: input.poolId,
      hashRate: input.hashRate
    }).$returningId();
    await db.update(miningPools).set({ totalMiners: sql23`totalMiners + 1` }).where(eq31(miningPools.id, input.poolId));
    return { id: pos.id, status: "started" };
