        { id: "prop_5", title: "Mining Farm Warehouse", city: "Wyoming", price: 89e4, cryptoPrice: 13.7, type: "buy", beds: 0, baths: 2, sqft: 15e3, tokenized: true, tokens: 2e3, tokenPrice: 445 }
